#!/usr/bin/env Rscript
suppressPackageStartupMessages({library(Matrix);library(data.table);library(jsonlite)})
parse_args<-function(x){o<-list();i<-1L;while(i<=length(x)){k<-sub("^--","",x[i]);if(i==length(x)||startsWith(x[i+1],"--")){o[[k]]<-TRUE;i<-i+1L}else{o[[k]]<-x[i+1];i<-i+2L}};o};a<-parse_args(commandArgs(trailingOnly=TRUE));need<-c("rds","membership","out","cell-id-col");miss<-need[!need%in%names(a)];if(length(miss))stop("Missing: ",paste(miss,collapse=", "));dir.create(a$out,recursive=TRUE,showWarnings=FALSE);read_any<-function(p)if(grepl("\\.gz$",p))fread(cmd=paste("gzip -dc",shQuote(p)))else fread(p)
obj<-readRDS(a$rds);mem<-read_any(a$membership);cc<-a$`cell-id-col`;mem[[cc]]<-as.character(mem[[cc]]);if(uniqueN(mem[[cc]])!=nrow(mem))stop("duplicate membership IDs");ids<-intersect(colnames(obj),mem[[cc]]);if(length(ids)!=nrow(mem))stop("membership mismatch");mem<-mem[match(ids,get(cc))]
if(inherits(obj,"Seurat")){if(!requireNamespace("SeuratObject",quietly=TRUE))stop("SeuratObject required");an<-ifelse(is.null(a$assay),SeuratObject::DefaultAssay(obj),a$assay);layer<-ifelse(is.null(a$`count-assay`),"counts",a$`count-assay`);mat<-tryCatch(SeuratObject::LayerData(obj[[an]],layer=layer),error=function(e)SeuratObject::GetAssayData(obj[[an]],slot=layer))[,ids,drop=FALSE]} else if(inherits(obj,"SummarizedExperiment")){an<-ifelse(is.null(a$`count-assay`),"counts",a$`count-assay`);mat<-SummarizedExperiment::assay(obj,an)[,ids,drop=FALSE]}else stop("Unsupported object class")
mat<-as(mat,"dgCMatrix");writeMM(mat,file.path(a$out,"counts_genes_by_observations.mtx"));fwrite(data.table(gene=rownames(mat)),file.path(a$out,"features.tsv"),sep="\t");fwrite(mem,file.path(a$out,"observations.tsv"),sep="\t");write_json(list(source_rds=normalizePath(a$rds),source_class=class(obj),count_assay=an,n_genes=nrow(mat),n_observations=ncol(mat),orientation="genes_by_observations",warning="Conversion adapter only; source object remains authoritative."),file.path(a$out,"export_manifest.json"),pretty=TRUE,auto_unbox=TRUE)
